#include <bits/stdc++.h> 
using namespace std;
const int N=100005,mod=10007;
long long n,m,a[N],c[N],num[N][2],ca[N][2],all[N][2],idall[N][2],ans;//ca i 0/1 x*col[x]
void fun(long long &x,long long y)
{
	x=(x+y)%mod;
}
int main()
{
	cin>>n>>m;
	for(int i=1;i<=n;i++) cin>>a[i];
	for(int i=1;i<=n;i++)
	{
		a[i]%=mod;
		long long t=i%2,t2=(i*a[i])%mod;
		cin>>c[i];
		fun(ans,(ca[c[i]][t]+(num[c[i]][t]*t2)%mod+(idall[c[i]][t]*a[i])%mod+(all[c[i]][t]*i)%mod)%mod);
		fun(ca[c[i]][t],t2);
		fun(all[c[i]][t],a[i]);
		fun(idall[c[i]][t],i);
		fun(num[c[i]][t],1);
	}
	cout<<ans;
	return 0;
}
